document['addEventListener']('DOMContentLoaded',function(){const g=document['querySelectorAll']('.date-control');g['forEach']((A,x)=>{A['addEventListener']('keydown',function(G){if('Tab'===G['key']){if(G['preventDefault'](),G['shiftKey']){const f=g[x-0x1];f&&f['focus']();}else{const d=g[x+0x1];d&&d['focus']();}}});});});